/* com.erns.coching.board.mapper.BoardDAO.insertCmt */


			SELECT nextval('seq_t_board_cmt') AS boardCmtSeq,		
				COALESCE(MAX(SORT_ORD), 0) + 1 AS sortOrd,
				(SELECT COUNT(*) FROM T_BOARD_CMT WHERE BOARD_SEQ = #{boardSeq, jdbcType=INTEGER} AND REF_ID = #{refId, jdbcType=INTEGER}) AS cmtOrd
	        FROM T_BOARD_CMT
	        WHERE BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}


