		 #{boardCmtSeq, jdbcType=INTEGER}
		 ,#{boardSeq, jdbcType=INTEGER}
		 ,#{writer, jdbcType=VARCHAR}
		 ,#{content, jdbcType=VARCHAR}
		 ,#{delYn, jdbcType=CHAR}
		 ,


		 		#{refId, jdbcType=INTEGER}


		 		#{boardCmtSeq, jdbcType=INTEGER}


		 ,


		 		#{cmtOrd, jdbcType=INTEGER}


		 		1


		 ,#{sortOrd, jdbcType=INTEGER}
		 ,#{secretYn, jdbcType=CHAR}
		 ,#{rgtr, jdbcType=INTEGER}
		 , now()
	)

