/* com.erns.coching.board.mapper.BoardDAO.getInqrList */
SELECT ZZ.* FROM ( SELECT * , CASE WHEN (SELECT COUNT(*) FROM T_INQUIRY_INF WHERE ORG_SEQ = AA.BOARD_SEQ) > 0 THEN 'Y' ELSE 'N' END AS IS_REPLY , MEMB.NICKNAME AS REG_NAME FROM T_INQUIRY_INF AA LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ WHERE AA.RGTR = #{rgtr} AND AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N' ORDER BY AA.BOARD_SEQ DESC ) ZZ
OFFSET #{offset} LIMIT #{rowSize}

mapper.insert:
/* com.erns.coching.board.mapper.BoardDAO.insertInqr */


	SELECT nextval('seq_t_inquiry_inf')


INSERT INTO T_INQUIRY_INF (
	  BOARD_SEQ
	, BOARD_MST_ID
	, CATE_CD
	, TITLE
	, CONTENT
	, WRITER
	, PHONE
	, EMAIL
	, ORG_SEQ
	, SORT_ORD
	, DEL_YN
	, ADMIN_DEL_CD
	, ADMIN_DEL_RSN
	, VIEWS
	, FROM_DATE
	, TO_DATE
	, FIX_YN
	, RGTR
	, RGT_DTTM
	, CHNR
	, CHNG_DTTM
) VALUES (
	  #{boardSeq       , jdbcType=INTEGER}
	, #{boardMstId     , jdbcType=VARCHAR}
	, #{cateCd         , jdbcType=VARCHAR}
	, #{title          , jdbcType=VARCHAR}
	, #{content        , jdbcType=VARCHAR}
	, #{writer         , jdbcType=VARCHAR}
	, #{phone          , jdbcType=VARCHAR}
	, #{email          , jdbcType=VARCHAR}
	, COALESCE(#{orgSeq , jdbcType=INTEGER}, 0)
	, #{sortOrd        , jdbcType=INTEGER}
	, COALESCE(#{delYn , jdbcType=CHAR}, 'N')
	, #{adminDelCd     , jdbcType=VARCHAR}
	, #{adminDelRsn    , jdbcType=VARCHAR}
	, COALESCE(#{views , jdbcType=INTEGER}, 0)
	, #{fromDate       , jdbcType=VARCHAR}
	, #{toDate         , jdbcType=VARCHAR}
	, COALESCE(#{fixYn , jdbcType=CHAR}, 'N')
	, #{rgtr           , jdbcType=INTEGER}
	, now()
	, #{chnr           , jdbcType=INTEGER}
	, now()
)

mapper.select:
/* com.erns.coching.board.mapper.BoardDAO.loadInqrDetail */
SELECT AA.* , ( SELECT MIN(AA.BOARD_SEQ) FROM T_INQUIRY_INF AA WHERE AA.BOARD_SEQ > #{boardSeq, jdbcType=INTEGER} AND AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N' ) AS NEXT , ( SELECT MAX(AA.BOARD_SEQ) FROM T_INQUIRY_INF AA WHERE AA.BOARD_SEQ < #{boardSeq, jdbcType=INTEGER} AND AA.ORG_SEQ = 0 AND AA.DEL_YN = 'N' ) AS PREV , CD.CODE_NAME AS CATE_NM , MEMB.NICKNAME AS REG_NAME FROM T_INQUIRY_INF AA LEFT JOIN T_CODE_INF CD ON AA.CATE_CD = CD.ETC1 AND CD.GRP_CODE = 'CH015' AND CD.ETC5 = UPPER(#{locale, jdbcType=VARCHAR}) LEFT JOIN T_MEMB_INF MEMB ON AA.RGTR = MEMB.MEMB_SEQ
AND AA.BOARD_SEQ = #{boardSeq, jdbcType=INTEGER}

/* com.erns.coching.board.mapper.BoardDAO.loadInqrReply */

SELECT *
	FROM T_INQUIRY_INF AA

	AND AA.ORG_SEQ = #{boardSeq, jdbcType=INTEGER}
